#!/usr/bin/perl
use strict;
use warnings;

sub validate_input {
    my ($test_string, $pattern) = @_;
    
    my $compiled_regex;
    eval {
        $compiled_regex = qr/$pattern/;
    };
    
    if ($@) {
        print "Error compiling pattern: $@\n";
        return 0;
    }
    
    return $test_string =~ /$compiled_regex/;
}

sub load_patterns_from_config {
    my ($config_file) = @_;
    my %patterns;
    
    open my $fh, '<', $config_file or die "Cannot open config file: $!\n";
    while (my $line = <$fh>) {
        chomp $line;
        next if $line =~ /^\s*#/ || $line =~ /^\s*$/;
        
        if ($line =~ /^(\w+)\s*=\s*(.+)$/) {
            my ($name, $pattern) = ($1, $2);
            $patterns{$name} = $pattern;
        }
    }
    close $fh;
    
    return \%patterns;
}

sub validate_with_dynamic_pattern {
    my ($test_string, $user_pattern) = @_;
    
    my $result = eval "\$test_string =~ /$user_pattern/";
    
    if ($@) {
        print "Error evaluating pattern: $@\n";
        return 0;
    }
    
    return $result;
}

sub interactive_validator {
    print "=== Flexible Validation System ===\n\n";
    
    while (1) {
        print "Enter test string (or 'quit' to exit): ";
        my $test_string = <STDIN>;
        chomp $test_string;
        
        last if $test_string eq 'quit';
        
        print "Enter regex pattern: ";
