        }
    }
}

sub batch_validate {
    my ($strings_ref, $patterns_ref) = @_;
    
    print "\n=== Batch Validation Results ===\n";
    
    foreach my $pattern_name (keys %$patterns_ref) {
        my $pattern = $patterns_ref->{$pattern_name};
        print "\nPattern: $pattern_name => $pattern\n";
        
        foreach my $test_string (@$strings_ref) {
            my $result = validate_input($test_string, $pattern);
            my $status = $result ? "PASS" : "FAIL";
            print "  [$status] '$test_string'\n";
        }
    }
}

sub advanced_validation {
    my ($input, $pattern, $modifiers) = @_;
    
    my $regex_string = "/$pattern/$modifiers";
    my $match = eval "\$input =~ $regex_string";
    
    if ($@) {
