    return $match;
}

sub extract_captures {
    my ($input, $pattern) = @_;
    
    my @captures;
    eval {
        if ($input =~ /$pattern/) {
            @captures = ($1, $2, $3, $4, $5, $6, $7, $8, $9);
            @captures = grep { defined $_ } @captures;
        }
    };
    
    return @captures;
}

